nta.declaration:
// Place global declarations here.
// Constants
const int STALL_SPEED = 2000; // Example stall speed in m/s
const int ALT_DIFF_THRESHOLD = 10; // Altitude difference for Climb mode
const int ALT_GAIN_PITCH = 500; // Pitch up angle in Climb mode
const int THROTTLE_MAX = 10000; // Maximum throttle percentage
const int THROTTLE_RATE_LIMIT = 1000; // Max throttle rise per second
const int PITCH_MAX_LIMIT = 2000;    //Max limit on pitch angle
const int PITCH_MIN_LIMIT = -2000; //Min limit on pitch angle
const int ONE_SECOND = 100;
const int EXECUTION_RATE = 100; //1000 EXECUTIONS PER SECOND
// Global variables
int actualAltitude;
int referenceAltitude;
int actualAirspeed;
int referenceAirspeed;
int pitchAngle;
int engineThrottle;


// Clocks for timing
clock t_alt_diff; // For altitude difference duration
clock t_stall_speed; // For stall speed duration
clock t_exit_climb; // For exiting climb mode
clock t_stall_exit; // For exiting stall recovery mode
clock t_throttle_update; // For throttle rate limiting

// Channels for synchronization
chan enterClimb, exitClimb, enterStallRecovery, exitStallRecovery;
chan sensorUpdate;

template.declaration:
int count;
void updateSensorReadings()
{
    referenceAltitude = 1000; // + fint(random(100));
    referenceAirspeed = 2000; // + fint(random(50));
    actualAltitude = referenceAltitude - 50*count; // + fint(random(10))); // Simulate altitude changes
    //actualAltitude = 500;
    actualAirspeed = referenceAirspeed - 100; //(-2 + fint(random(4))); // Simulate airspeed changes
    //actualAirspeed = 1000;
    if (actualAltitude < 0) actualAltitude = 0; // Altitude can't be negative
    if (actualAirspeed < 0) actualAirspeed = 0; // Airspeed can't be negative

    count++;
    if(count >= 20) count = 0;
}

// Place local declarations here.

void updateThrottle(int newThrottle)
{

    if(newThrottle > (engineThrottle + THROTTLE_RATE_LIMIT/EXECUTION_RATE))
    {
        engineThrottle = engineThrottle + THROTTLE_RATE_LIMIT/EXECUTION_RATE;
    }
    else 
    {
        engineThrottle = newThrottle; 
    }

    if(engineThrottle > THROTTLE_MAX) engineThrottle = THROTTLE_MAX;
}

void updatePitch()
{
    int altDiff = referenceAltitude - actualAltitude;
    pitchAngle = altDiff/10;
    if(pitchAngle > PITCH_MAX_LIMIT) pitchAngle = PITCH_MAX_LIMIT;
    if(pitchAngle < PITCH_MIN_LIMIT) pitchAngle = PITCH_MIN_LIMIT;   
}

void updatePitchAndThrottleNormal()
{
    int diffSpeed;
    int altDiff = referenceAltitude - actualAltitude;
    //if(altDiff < ALT_DIFF_THRESHOLD)
    //    t_alt_diff = 0;
    updatePitch();
    //Handle setThrottle
    diffSpeed = referenceAirspeed - actualAirspeed;
    updateThrottle(diffSpeed/10);

    //if(actualAirspeed >= STALL_SPEED)
    //    t_stall_speed = 0;
}

void updatePitchAndThrottleClimb()
{
    double altDiff = referenceAltitude - actualAltitude;
    //if(altDiff > 0.0)
    //    t_exit_climb = 0;
    pitchAngle = ALT_GAIN_PITCH;
    updateThrottle(100);

    //if(actualAirspeed >= STALL_SPEED)
    //    t_stall_speed = 0;
}

void updatePitchAndThrottleStallRecovery()
{
    updatePitch();
    if(pitchAngle > 0) pitchAngle = 0;
    updateThrottle(100);

    //if(actualAirspeed < (STALL_SPEED + 5))
     //   t_stall_exit = 0;
}

nta.system:
// Place template instantiations here.
system FCC_Mode_Manager, Sensor;

